"""Иммутабельные DTO."""from __future__ import annotationsfrom dataclasses import dataclass, fieldfrom typing import Anyimport numpy as npfrom numpy.typing import NDArray@dataclass(frozen=True, eq=False)class Signal:    t: NDArray[np.float64]    x: NDArray[np.float64]    fs: float    name: str    params: dict[str, Any] = field(default_factory=dict)    @property    def n_samples(self) -> int:        return int(self.x.shape[0])    @property    def duration(self) -> float:        return float(self.n_samples / self.fs) if self.fs > 0 else 0.0@dataclass(frozen=True)class NoiseSpec:    name: str    params: dict[str, Any]    target_snr_db: float@dataclass(frozen=True)class FilterSpec:    name: str    params: dict[str, Any]@dataclass(frozen=True)class Metrics:    mse: float    rmse: float    snr_before_db: float    snr_after_db: float    snr_improvement_db: float    correlation: float@dataclass(frozen=True, eq=False)class ExperimentResult:    clean: Signal    noisy: Signal    restored: Signal    metrics: Metrics    signal_name: str    noise_name: str    filter_name: str    timestamp: str    # Новые поля (со значениями по умолчанию — не ломают старое API).    trial_index: int = 0      # номер испытания внутри серии (0..N-1)    seed: int = 0             # реально использованный seed в этом испытании@dataclass(frozen=True)class AggregatedMetrics:    """Агрегат метрик по набору ExperimentResult (по одному фильтру)."""    filter_name: str    n_trials: int    mse_mean: float    mse_std: float    rmse_mean: float    rmse_std: float    snr_before_db_mean: float    snr_before_db_std: float    snr_after_db_mean: float    snr_after_db_std: float    snr_improvement_db_mean: float    snr_improvement_db_std: float    correlation_mean: float    correlation_std: float@dataclass(frozen=True, eq=False)class ExperimentSeries:    """Серия экспериментов: одинаковый сигнал/шум, 1..M фильтров, 1..N испытаний.    Структура:        results[filter_name] = [ExperimentResult, ...]  # длины = n_trials        aggregates[filter_name] = AggregatedMetrics    """    signal_name: str    noise_name: str    filter_names: list[str]    n_trials: int    seed_mode: str                        # "manual" | "auto"    base_seed: int                        # для auto: 0; для manual: введённый seed    timestamp: str    results: dict[str, list[ExperimentResult]]    aggregates: dict[str, "AggregatedMetrics"]    def iter_results(self):        """Линейный обход всех результатов: (filter_name, trial_index, result)."""        for fname in self.filter_names:            for r in self.results.get(fname, []):                yield fname, r.trial_index, r    @property    def last_result(self) -> ExperimentResult | None:        """Последний результат последнего фильтра (для отображения на вкладках)."""        if not self.filter_names:            return None        last_filter = self.filter_names[-1]        runs = self.results.get(last_filter, [])        return runs[-1] if runs else None    @property    def total_runs(self) -> int:        return sum(len(v) for v in self.results.values())